// Update DashboardMetrics interface
export interface DashboardMetrics {
  total_executions: number;
  pass_rate: number;
  failure_rate: number;        // NEW
  avg_duration_ms: number;
  critical_failures: number;
  last_24h_executions: number;
  failure_volume: number;      // NEW: failure_rate * total_executions / 100
}

// New interface for failure trends
export interface FailureTrendData {
  date: string;
  failure_rate: number;
  total_tests: number;
  failed_tests: number;
}

database_functions.function:
export async function getDashboardMetrics( dateFrom?: string, dateTo?: string ): Promise<DashboardMetrics> { const sql = getSql();
const result = await sql` WITH execution_stats AS ( SELECT COUNT(*) as total_executions, COUNT(*) FILTER (WHERE status = 'success') as successful, COUNT(*) FILTER (WHERE status = 'failure') as failed, AVG(duration_ms) as avg_duration FROM test_executions WHERE (${dateFrom || null}::text IS NULL OR started_at >= ${dateFrom}::timestamptz) AND (${dateTo || null}::text IS NULL OR started_at <= ${dateTo}::timestamptz) ), recent_stats AS ( SELECT COUNT(*) FILTER ( WHERE status = 'failure' AND started_at > NOW() - INTERVAL '7 days' ) as critical_failures, COUNT(*) FILTER ( WHERE started_at > NOW() - INTERVAL '24 hours' ) as last_24h_executions FROM test_executions ) SELECT es.total_executions, CASE WHEN es.total_executions > 0 THEN ROUND(es.successful::decimal / es.total_executions * 100, 1) ELSE 0 END as pass_rate, CASE WHEN es.total_executions > 0 THEN ROUND(es.failed::decimal / es.total_executions * 100, 1) ELSE 0 END as failure_rate, COALESCE(ROUND(es.avg_duration), 0) as avg_duration_ms, rs.critical_failures, rs.last_24h_executions, CASE WHEN es.total_executions > 0 THEN ROUND(es.failed::decimal / es.total_executions * 100 * es.total_executions / 100, 1) ELSE 0 END as failure_volume FROM execution_stats es, recent_stats rs `;
return { total_executions: Number(result[0].total_executions), pass_rate: Number(result[0].pass_rate), failure_rate: Number(result[0].failure_rate), avg_duration_ms: Number(result[0].avg_duration_ms), critical_failures: Number(result[0].critical_failures), last_24h_executions: Number(result[0].last_24h_executions), failure_volume: Number(result[0].failure_volume) }; }

export async function getFailureTrendData( days: number = 7, dateFrom?: string, dateTo?: string ): Promise<FailureTrendData[]> { const sql = getSql();
const results = await sql` SELECT DATE(started_at) as date, COUNT(*) as total_tests, COUNT(*) FILTER (WHERE status = 'failure') as failed_tests, CASE WHEN COUNT(*) > 0 THEN ROUND(COUNT(*) FILTER (WHERE status = 'failure')::decimal / COUNT(*) * 100, 2) ELSE 0 END as failure_rate FROM test_executions WHERE status != 'running' AND ( CASE WHEN ${dateFrom}::text IS NOT NULL AND ${dateTo}::text IS NOT NULL THEN started_at >= ${dateFrom}::timestamptz AND started_at <= ${dateTo}::timestamptz ELSE started_at >= NOW() - (${days} || ' days')::interval END ) GROUP BY DATE(started_at) ORDER BY date ASC `;
return results as FailureTrendData[]; }

api_routes.route:

import { getTrendData, getFailureTrendData } from "@/lib/db";
import { NextRequest, NextResponse } from "next/server";

export const dynamic = "force-dynamic";

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const days = parseInt(searchParams.get("days") || "7");
    const dateFrom = searchParams.get("dateFrom") || undefined;
    const dateTo = searchParams.get("dateTo") || undefined;
    const type = searchParams.get("type") || "tests"; // "tests" or "failures"

    if (type === "failures") {
      const failureTrends = await getFailureTrendData(days, dateFrom, dateTo);
      return NextResponse.json(failureTrends);
    }

    const trends = await getTrendData(days, dateFrom, dateTo);
    return NextResponse.json(trends);
  } catch (error) {
    console.error("Error fetching trends:", error);
    return NextResponse.json(
      { error: "Failed to fetch trends" },
      { status: 500 }
    );
  }
}

components.component:

import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
  CheckCircle2,
  XCircle,
  Clock,
  AlertTriangle,
} from "lucide-react";

interface DashboardMetrics {
  total_executions: number;
  pass_rate: number;
  failure_rate: number;
  avg_duration_ms: number;
  critical_failures: number;
  last_24h_executions: number;
  failure_volume: number;
}

interface StatsCardsProps {
  metrics: DashboardMetrics;
}

export function StatsCards({ metrics }: StatsCardsProps) {
  const formatDuration = (ms: number) => {
    if (ms < 1000) return `${ms}ms`;
    if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
    return `${(ms / 60000).toFixed(1)}m`;
  };

  const cards = [
    {
      title: "Pass Rate",
      value: `${metrics.pass_rate}%`,
      icon: CheckCircle2,
      description: `${metrics.total_executions} total runs`,
      trend: metrics.pass_rate >= 90 ? "positive" : metrics.pass_rate >= 70 ? "neutral" : "negative",
    },
    {
      title: "Failure Rate",
      value: `${metrics.failure_rate}%`,
      icon: XCircle,
      description: `Volume: ${metrics.failure_volume.toFixed(1)}`,
      trend: metrics.failure_rate <= 5 ? "positive" : metrics.failure_rate <= 15 ? "neutral" : "negative",
    },
    {
      title: "Avg Duration",
      value: formatDuration(metrics.avg_duration_ms),
      icon: Clock,
      description: "per execution",
      trend: "neutral",
    },
    {
      title: "Critical Failures",
      value: metrics.critical_failures.toString(),
      icon: AlertTriangle,
      description: "last 7 days",
      trend: metrics.critical_failures === 0 ? "positive" : metrics.critical_failures <= 3 ? "neutral" : "negative",
    },
  ];

  const getTrendColor = (trend: string) => {
    switch (trend) {
      case "positive":
        return "text-green-500";
      case "negative":
        return "text-red-500";
      default:
        return "text-muted-foreground";
    }
  };

  const getTrendBg = (trend: string) => {
    switch (trend) {
      case "positive":
        return "bg-green-500/10";
      case "negative":
        return "bg-red-500/10";
      default:
        return "bg-muted";
    }
  };

  return (
    <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
      {cards.map((card) => (
        <Card key={card.title}>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{card.title}</CardTitle>
            <div className={`p-2 rounded-full ${getTrendBg(card.trend)}`}>
              <card.icon className={`h-4 w-4 ${getTrendColor(card.trend)}`} />
            </div>
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{card.value}</div>
            <p className="text-xs text-muted-foreground">{card.description}</p>
          </CardContent>
        </Card>
      ))}
    </div>
  );
}


"use client";

import { useEffect, useState } from "react";
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  ReferenceLine,
} from "recharts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { TrendingDown } from "lucide-react";

interface FailureTrendData {
  date: string;
  failure_rate: number;
  total_tests: number;
  failed_tests: number;
}

interface FailureRateChartProps {
  dateFrom?: string;
  dateTo?: string;
}

export function FailureRateChart({ dateFrom, dateTo }: FailureRateChartProps) {
  const [data, setData] = useState<FailureTrendData[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        const params = new URLSearchParams({ type: "failures" });
        if (dateFrom) params.set("dateFrom", dateFrom);
        if (dateTo) params.set("dateTo", dateTo);

        const response = await fetch(`/api/trends?${params.toString()}`);
        const json = await response.json();
        setData(json);
      } catch (error) {
        console.error("Failed to fetch failure trends:", error);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, [dateFrom, dateTo]);

  const formattedData = data.map((item) => ({
    ...item,
    date: new Date(item.date).toLocaleDateString("en-US", {
      month: "short",
      day: "numeric",
    }),
  }));

  const avgFailureRate =
    data.length > 0
      ? data.reduce((sum, d) => sum + d.failure_rate, 0) / data.length
      : 0;

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <TrendingDown className="h-5 w-5" />
            Failure Rate Trend
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-[200px] bg-muted animate-pulse rounded" />
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center justify-between">
          <span className="flex items-center gap-2">
            <TrendingDown className="h-5 w-5" />
            Failure Rate Trend
          </span>
          <span className="text-sm font-normal text-muted-foreground">
            Avg: {avgFailureRate.toFixed(1)}%
          </span>
        </CardTitle>
      </CardHeader>
      <CardContent>
        <ResponsiveContainer width="100%" height={200}>
          <LineChart data={formattedData}>
            <CartesianGrid strokeDasharray="3 3" className="stroke-muted" />
            <XAxis
              dataKey="date"
              tick={{ fontSize: 12 }}
              className="text-muted-foreground"
            />
            <YAxis
              tick={{ fontSize: 12 }}
              tickFormatter={(value) => `${value}%`}
              className="text-muted-foreground"
              domain={[0, "auto"]}
            />
            <Tooltip
              content={({ active, payload }) => {
                if (active && payload && payload.length) {
                  const data = payload[0].payload;
                  return (
                    <div className="bg-popover border rounded-lg p-2 shadow-lg">
                      <p className="font-medium">{data.date}</p>
                      <p className="text-red-500">
                        Failure Rate: {data.failure_rate.toFixed(1)}%
                      </p>
                      <p className="text-xs text-muted-foreground">
                        {data.failed_tests} / {data.total_tests} executions
                      </p>
                    </div>
                  );
                }
                return null;
              }}
            />
            <ReferenceLine
              y={avgFailureRate}
              stroke="#888"
              strokeDasharray="3 3"
              label={{
                value: "Avg",
                position: "right",
                fontSize: 10,
              }}
            />
            <Line
              type="monotone"
              dataKey="failure_rate"
              stroke="#ef4444"
              strokeWidth={2}
              dot={{ fill: "#ef4444", strokeWidth: 2, r: 4 }}
              activeDot={{ r: 6 }}
            />
          </LineChart>
        </ResponsiveContainer>
      </CardContent>
    </Card>
  );
}

